export function getG7IngredientById(id: string) {
  return G7_MASTER_INGREDIENTS.find((ingredient) => ingredient.id === id)
}

export function getG7IngredientByRef(ref: string) {
  return G7_MASTER_INGREDIENTS.find((ingredient) => ingredient.ref === ref)
}

export function getG7IngredientsByCategory(category: G7IngredientCategory) {
  return G7_MASTER_INGREDIENTS.filter(
    (ingredient) => ingredient.category === category
  )
}

export function searchG7Ingredients(query: string) {
  const normalizedQuery = query.trim().toLowerCase()

  if (!normalizedQuery) return G7_MASTER_INGREDIENTS

  return G7_MASTER_INGREDIENTS.filter((ingredient) => {
    return (
      ingredient.name.toLowerCase().includes(normalizedQuery) ||
      ingredient.id.toLowerCase().includes(normalizedQuery) ||
      ingredient.ref.toLowerCase().includes(normalizedQuery) ||
      ingredient.arabicName.toLowerCase().includes(normalizedQuery)
    )
  })
}

export function calculateG7IngredientMacros(
  ingredientId: string,
  amountInGrams: number
) {
  const ingredient = getG7IngredientById(ingredientId)

  if (!ingredient) {
    throw new Error(`G7 ingredient not found: ${ingredientId}`)
  }

  const factor = amountInGrams / 100

  return {
    kcal: Math.round(ingredient.kcalPer100 * factor),
    protein: Number((ingredient.proteinPer100 * factor).toFixed(1)),
    carbs: Number((ingredient.carbsPer100 * factor).toFixed(1)),
    fat: Number((ingredient.fatPer100 * factor).toFixed(1)),
    fiber: Number((ingredient.fiberPer100 * factor).toFixed(1)),
    sodium: Number((ingredient.sodiumPer100 * factor).toFixed(1)),
    cost: Number((ingredient.pricePer100g * factor).toFixed(2)),
  }
}

export function calculatePreparedWeight(
  ingredientId: string,
  rawWeightInGrams: number
) {
  const ingredient = getG7IngredientById(ingredientId)

  if (!ingredient) {
    throw new Error(`G7 ingredient not found: ${ingredientId}`)
  }

  return Number((rawWeightInGrams * ingredient.prepYield).toFixed(1))
}
